#include <OneWire.h>
#include <DallasTemperature.h>
#include <Wire.h>
#include <Adafruit_BMP280.h>
#include <SD.h>
#define HEATER_PIN 9
#define OW_PIN 2
#define SD_CS 10
#define T_START 30.0f
#define T_STEP 5.0f
#define N_STEPS 8
#define EQUIL_MS 300000UL
#define FAULT_TEMP 75.0f
OneWire ow(OW_PIN); DallasTemperature ds(&ow);
Adafruit_BMP280 bmp; File lg;
float lnPArr[N_STEPS], invTArr[N_STEPS];
int stepIdx=0; unsigned long stepStart=0;
float clausius_clapeyron_fit(float*lnP,float*invT,int n,float*slope){
  float sx=0,sy=0,sxy=0,sx2=0;
  for(int i=0;i<n;i++){sx+=invT[i];sy+=lnP[i];sxy+=invT[i]*lnP[i];sx2+=invT[i]*invT[i];}
  float denom=n*sx2-sx*sx; if(denom==0){*slope=0;return 0;}
  *slope=(n*sxy-sx*sy)/denom;
  float b=(sy-*slope*sx)/n,sstot=0,ssres=0,ymean=sy/n;
  for(int i=0;i<n;i++){float yh=*slope*invT[i]+b;ssres+=(lnP[i]-yh)*(lnP[i]-yh);sstot+=(lnP[i]-ymean)*(lnP[i]-ymean);}
  return (sstot>0)?1.0f-ssres/sstot:1.0f;
}
void initHardware(){
  pinMode(HEATER_PIN,OUTPUT); ds.begin(); bmp.begin();
  SD.begin(SD_CS); lg=SD.open("pvt.csv",FILE_WRITE);
  if(lg) lg.println("step,T_C,P_Pa,lnP,invT");
  Serial.begin(9600); stepStart=millis();
}
float readTemperatureSensor(){ ds.requestTemperatures(); return ds.getTempCByIndex(0); }
float readPressureSensor(){ return bmp.readPressure(); }
void setHeaterBangBang(float sp, float pv){
  analogWrite(HEATER_PIN,(pv<sp-0.5f)?200:0);
}
void logStepData(int s, float T, float P){
  float lnP=log(P), invT=1.0f/(T+273.15f);
  lnPArr[s]=lnP; invTArr[s]=invT;
  if(lg){lg.print(s);lg.print(',');lg.print(T,2);lg.print(',');lg.print(P,1);lg.print(',');lg.print(lnP,5);lg.print(',');lg.println(invT,7);lg.flush();}
  Serial.print("S=");Serial.print(s);Serial.print(" T=");Serial.print(T,2);Serial.print(" P=");Serial.println(P,1);
}
void checkFaultSafety(float T){ if(T>FAULT_TEMP){analogWrite(HEATER_PIN,0);Serial.println("FAULT:OVERTEMP");while(1);} }
void setup(){ initHardware(); }
void loop(){
  if(stepIdx>=N_STEPS){
    float slope=0;
    float r2=clausius_clapeyron_fit(lnPArr,invTArr,N_STEPS,&slope);
    float dHvap=-slope*8.314f;
    Serial.print("dHvap=");Serial.print(dHvap/1000.0f,2);Serial.print("kJ/mol R2=");Serial.println(r2,4);
    if(lg){lg.print("dHvap_kJ=");lg.print(dHvap/1000.0f,2);lg.print(" R2=");lg.println(r2,4);lg.close();}
    analogWrite(HEATER_PIN,0); while(1);
  }
  float sp=T_START+stepIdx*T_STEP;
  float T=readTemperatureSensor(); checkFaultSafety(T);
  setHeaterBangBang(sp,T);
  if(millis()-stepStart>EQUIL_MS){
    float P=readPressureSensor(); logStepData(stepIdx,T,P);
    stepIdx++; stepStart=millis();
  }
  delay(500);
}
